<h2 class="mb-4">📋 Dispatcher Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3 ms-auto text-end">
        <button class="btn btn-success" @onclick="ShowCreateForm">
            ➕ New Shipment
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-3">
                <div class="col-md-3">
                    <label class="form-label">Origin</label>
                    <input class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Destination</label>
                    <input class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Recipient</label>
                    <input class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Description</label>
                    <input class="form-control" @bind="newShipment.Description" />
                </div>
            </div>
            <div class="mt-3">
                <button class="btn btn-primary" @onclick="CreateShipment" disabled="@isCreating">
                    @(isCreating ? "Creating..." : "Create")
                </button>
                <button class="btn btn-secondary ms-2" @onclick="() => showCreateForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@s.Status"
                                    @onchange="(e) => UpdateStatus(s, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status" selected="@(s.Status == status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string filterStatus = string.Empty;
    private bool showCreateForm;
    private bool isCreating;
    private ShipmentDto newShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrWhiteSpace(filterText) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
             s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrWhiteSpace(filterStatus) ||
             s.Status.ToString() == filterStatus));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        newShipment = new ShipmentDto();
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        try
        {
            var created = await ShipmentService.CreateShipmentAsync(newShipment);
            shipments?.Insert(0, created);
            showCreateForm = false;
        }
        finally
        {
            isCreating = false;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            var index = shipments!.FindIndex(s => s.Id == shipment.Id);
            if (index >= 0)
                shipments[index] = updated;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2 class="mb-4">🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260101-10001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (hasSearched && shipment is null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment found with tracking number <code>@searchedNumber</code>.
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card shadow">
        <div class="card-header bg-primary text-white">
            <h5 class="mb-0">Shipment <code class="text-white">@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row g-4">
                <div class="col-md-6">
                    <h6>📍 Route</h6>
                    <p class="mb-1"><strong>From:</strong> @shipment.Origin</p>
                    <p class="mb-1"><strong>To:</strong> @shipment.Destination</p>
                    <p class="mb-0"><strong>Recipient:</strong> @shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <h6>📅 Dates</h6>
                    <p class="mb-1"><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMMM dd, yyyy")</p>
                    <p class="mb-1"><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</p>
                    @if (shipment.ActualDelivery.HasValue)
                    {
                        <p class="mb-0"><strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</p>
                    }
                </div>
            </div>

            <hr />

            <div class="row">
                <div class="col-md-6">
                    <h6>📦 Status</h6>
                    <span class="badge fs-6 @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                </div>
                <div class="col-md-6">
                    <h6>📝 Description</h6>
                    <p class="mb-0">@shipment.Description</p>
                </div>
            </div>

            <hr />

            <h6>Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(shipment.Status))%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool isSearching;
    private bool hasSearched;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        hasSearched = true;
        searchedNumber = trackingNumber.Trim();
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        }
        finally
        {
            isSearching = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

